/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
[ExtensionOf(formDataSourcestr(EcoResProductDetailsExtended,InventTable))]
internal final class ETGEcoResProductDetailsExtendedFormInventTableDSDMS_Extension
{
}

Method.Source:
/// <summary>
///  Freezes the form fields by updating the design when the data source is activated.
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = next active();

    ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);

    if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
    {
        // Disable the control InventoryTracking_BatchNumGroupId
        FormRun formRun = this.formRun();
        FormStringControl batchNumGroupControl = formRun.control(formRun.controlId("InventoryTracking_BatchNumGroupId")) as FormStringControl;
        FormContainerControl dimensionEntryControl = formRun.control(formRun.controlId("DimensionEntryControl")) as FormContainerControl;

        if (batchNumGroupControl)
        {
            batchNumGroupControl.enabled(false);
        }
        if (dimensionEntryControl)
        {
            dimensionEntryControl.enabled(false);
        }
    }

    return ret;

}
